public void validate(Answer<?> answer, Invocation invocation) {
        if (answer instanceof ThrowsException) {
            validateException((ThrowsException) answer, invocation);
        }

        if (answer instanceof Returns) {
            validateReturnValue((Returns) answer, invocation);
        }

        if (answer instanceof DoesNothing) {
            validateDoNothing((DoesNothing) answer, invocation);
        }

        if (answer instanceof CallsRealMethods) {
            if (invocation != null && invocation.getMethod() != null && invocation.getMethod().getDeclaringClass().isInterface()) {
                throw new MockitoException("Cannot call real method on interface");
            }
        }

    }
